<?php
namespace Tests\Feature\Accounting;
use App\Domain\Accounting\Actions\PostJournal;use App\Domain\Accounting\Actions\ProvisionAccounting;use App\Domain\Accounting\Services\FinancialReports;use App\Models\Cooperative;use App\Models\LedgerAccount;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class FinancialReportsTest extends TestCase{use RefreshDatabase;public function test_trial_balance_and_income_statement_derive_from_posted_lines():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);app(ProvisionAccounting::class)->execute();$cash=LedgerAccount::query()->where('code','1000')->firstOrFail();$income=LedgerAccount::query()->where('code','4000')->firstOrFail();app(PostJournal::class)->execute(['entry_date'=>today()->toDateString(),'description'=>'Interest received','lines'=>[['ledger_account_id'=>$cash->id,'debit_minor'=>25000,'credit_minor'=>0],['ledger_account_id'=>$income->id,'debit_minor'=>0,'credit_minor'=>25000]]]);$reports=app(FinancialReports::class);$trial=$reports->trialBalance(today()->toDateString(),today()->toDateString());$this->assertTrue($trial['balanced']);$this->assertSame(25000,$trial['total_debit_minor']);$incomeStatement=$reports->incomeStatement(today()->toDateString(),today()->toDateString());$this->assertSame(25000,$incomeStatement['net_surplus_minor']);}}
